// Monta os LOTES do motor de bulas: cada lote tem até 2 documentos
// (texto completo). O catálogo compactado viaja junto em cada item.
const j = $input.first().json;
const catalogo = j.catalogo || [];
const docs = (j.docs || []).filter(d => d.file_id);
if (!catalogo.length) throw new Error('Catálogo vazio — cadastre as linhas antes de rodar o motor.');
if (!docs.length) throw new Error('Nenhum documento no RAG. Envie as bulas na aba Documentos antes.');

const linhas = catalogo.map(c =>
  `- "${c.linha}": ${c.descricao || ''} (finalidade: ${c.finalidade || '-'}). Termos fortes atuais: ${(c.termos_fortes || []).join(', ') || 'nenhum'}.`
).join('\n');

const TAM_LOTE = 2;
const out = [];
for (let i = 0; i < docs.length; i += TAM_LOTE) {
  const lote = docs.slice(i, i + TAM_LOTE);
  out.push({ json: {
    lote_num: Math.floor(i / TAM_LOTE) + 1,
    total_lotes: Math.ceil(docs.length / TAM_LOTE),
    titulos: lote.map(d => d.titulo),
    // file_id vem do nosso próprio banco; sanitiza mesmo assim
    file_ids_sql: lote.map(d => `'${String(d.file_id).replace(/'/g, '')}'`).join(','),
    catalogoLinhas: linhas
  } });
}
return out;

const meta = $('Loop Lotes').first().json;
const rows = $input.all().map(i => i.json).filter(r => r.texto && String(r.texto).trim() !== '');
if (!rows.length) {
  // lote sem texto (docs vazios) — segue o loop sem chamar o LLM
  return [{ json: { prompt: '', vazio: true } }];
}

let docs = '';
for (const r of rows) {
  docs += `\n### ${r.titulo || 'documento'}\n${String(r.texto).replace(/\s+/g, ' ')}\n`;
}

const prompt = [
  'Você é especialista em licitações de produtos para diagnóstico in vitro (IVD) no Brasil.',
  'A NL Diagnóstica tem as linhas de catálogo abaixo. A partir das BULAS fornecidas (texto completo), extraia conhecimento para identificar itens de edital compatíveis com cada linha.',
  '',
  'LINHAS DO CATÁLOGO:',
  meta.catalogoLinhas,
  '',
  'REGRAS:',
  '- termos_fortes: expressões ESPECÍFICAS e decisivas que, sozinhas, indicam que o item é desta linha (nome do exame/analito, metodologia, nome comercial do equipamento, tipo de reagente). Ex.: "tempo de protrombina", "eletroforese capilar". MÍNIMO de 4 caracteres — siglas curtas (tca, tp, inr, mic, spe) NÃO podem ser termo forte: coloque-as em sinonimos.',
  '- sinonimos: variações de escrita dos termos fortes (com/sem acento, sigla, nome em inglês usado em editais brasileiros).',
  '- palavras_chave: termos de apoio que reforçam o match mas não decidem sozinhos.',
  '- contexto: 2 a 4 frases descrevendo o que ESTAS bulas mostram sobre a linha (exames cobertos, metodologia, equipamentos, marcas, apresentações). Só inclua se as bulas deste lote forem desta linha.',
  '- NÃO inclua palavras genéricas (reagente, teste, kit, controle, laboratório, equipamento, análise, coleta, amostra, qualidade) nem nomes de doenças isolados.',
  '- Tudo em minúsculas (exceto o contexto), pt-BR, sem pontuação final nos termos. Use apenas linhas EXATAMENTE como listadas acima.',
  '- Não repita termos fortes que a linha já possui.',
  '',
  'BULAS DESTE LOTE:',
  docs,
  '',
  'Responda APENAS com um array JSON válido, sem markdown, no formato:',
  '[{"linha":"<linha exata>","termos_fortes":["..."],"sinonimos":["..."],"palavras_chave":["..."],"contexto":"..."}]'
].join('\n');

return [{ json: { prompt, vazio: false } }];

// Lote sem texto — manda um payload neutro só para fechar o ciclo do loop.
const b64 = Buffer.from(JSON.stringify({ linha: '' }), 'utf8').toString('base64');
return [{ json: { linha: '(lote vazio)', b64 } }];

// Tolerante a falhas: num motor em lotes, um lote ruim NÃO pode derrubar o loop.
const raw = String($input.first().json.text || '').trim();
const neutro = () => [{ json: { linha: '(sem resultado)', b64: Buffer.from(JSON.stringify({ linha: '' }), 'utf8').toString('base64') } }];
const m = raw.match(/\[[\s\S]*\]/);
if (!m) return neutro();
let arr;
try { arr = JSON.parse(m[0]); } catch (e) { return neutro(); }
if (!Array.isArray(arr) || !arr.length) return neutro();
const out = [];
for (const it of arr) {
  if (!it || !it.linha) continue;
  const payload = {
    linha: String(it.linha),
    termos_fortes: Array.isArray(it.termos_fortes) ? it.termos_fortes : [],
    sinonimos: Array.isArray(it.sinonimos) ? it.sinonimos : [],
    palavras_chave: Array.isArray(it.palavras_chave) ? it.palavras_chave : [],
    contexto: typeof it.contexto === 'string' ? it.contexto.trim() : ''
  };
  out.push({ json: { linha: payload.linha, b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64') } });
}
return out.length ? out : neutro();

// Agrega o resultado de TODOS os lotes do motor (cada iteração do loop
// é um runIndex diferente do nó 'Merge Catálogo').
const porLinha = {};
let fortes = 0, sin = 0, chave = 0, contextos = 0, naoEnc = 0, lotes = 0;
for (let run = 0; run < 1000; run++) {
  let items;
  try { items = $('Merge Catálogo').all(0, run); } catch (e) { break; }
  if (!items || !items.length) break;
  lotes++;
  for (const item of items) {
    const r = item.json.resultado || item.json;
    if (!r || !r.linha) continue;
    if (!r.encontrado) { if (r.linha) naoEnc++; continue; }
    const f = (r.adicionados_fortes || []).length;
    const s = (r.adicionados_sinonimos || []).length;
    const k = (r.adicionados_chave || []).length;
    fortes += f; sin += s; chave += k;
    if (r.contexto_adicionado) contextos++;
    if (f || s || k || r.contexto_adicionado) {
      const l = (porLinha[r.linha] = porLinha[r.linha] || { linha: r.linha, termos_fortes: [], sinonimos: [] });
      l.termos_fortes.push(...(r.adicionados_fortes || []));
      l.sinonimos.push(...(r.adicionados_sinonimos || []));
    }
  }
}
return [{ json: {
  status: 'ok',
  lotes_processados: lotes,
  linhas_atualizadas: Object.keys(porLinha).length,
  linhas_nao_encontradas: naoEnc,
  termos_fortes_adicionados: fortes,
  sinonimos_adicionados: sin,
  palavras_chave_adicionadas: chave,
  contextos_adicionados: contextos,
  detalhe: Object.values(porLinha)
} }];

const b = $input.first().json || {};
const body = b.body || b;
const id = String(body.edital_id || '').trim();
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id)) {
  throw new Error('edital_id (uuid) é obrigatório.');
}
return [{ json: { edital_id: id } }];

const j = $input.first().json;
if (!j || !j.edital) throw new Error('Edital não encontrado.');
const url = String(j.edital.url_edital || '').trim();
const has_url = /^https?:\/\//i.test(url);
return [{ json: { edital_id: j.edital.id, url, has_url } }];

const bin = $input.item.binary && $input.item.binary.data;
let is_pdf = false;
if (bin) {
  const mt = (bin.mimeType || '').toLowerCase();
  const fn = (bin.fileName || '').toLowerCase();
  is_pdf = mt.includes('pdf') || fn.endsWith('.pdf');
  if (!is_pdf) {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
      is_pdf = !!buf && buf.slice(0, 5).toString('latin1').startsWith('%PDF');
    } catch (e) {}
  }
}
return { json: { is_pdf }, binary: $input.item.binary || {} };

// PDF digitalizado: manda para OCR (Azure OpenAI Responses API).
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
if (!buffer || buffer.length > 20 * 1024 * 1024) {
  return { json: { ocr_body: null } };
}
const b64 = buffer.toString('base64');
const ocr_body = {
  model: 'REPLACE_ME_OCR_DEPLOYMENT',
  input: [
    {
      role: 'user',
      content: [
        { type: 'input_text', text: 'Extraia TODO o texto deste edital de licitação em português, preservando a ordem de leitura. Responda apenas com o texto, sem comentários.' },
        { type: 'input_file', filename: 'edital.pdf', file_data: 'data:application/pdf;base64,' + b64 }
      ]
    }
  ]
};
return { json: { ocr_body } };

const r = $input.first().json || {};
let text = '';
try {
  if (Array.isArray(r.output)) {
    for (const o of r.output) {
      if (Array.isArray(o.content)) {
        for (const c of o.content) { if (c.text) text += c.text; }
      }
    }
  }
  text = text || r.output_text || (r.choices && r.choices[0] && r.choices[0].message && r.choices[0].message.content) || '';
} catch (e) {}
return [{ json: { ocr_text: text } }];

const raw = String($input.first().json.text || '').trim();
const m = raw.match(/\{[\s\S]*\}/);
if (!m) throw new Error('LLM não retornou JSON. Início: ' + raw.slice(0, 200));
let analise;
try { analise = JSON.parse(m[0]); } catch (e) { throw new Error('JSON inválido do LLM: ' + e.message); }
const meta = $('Montar Análise').first().json;
analise.fonte_analise = meta.fonte_analise;
analise.gerado_em = new Date().toISOString();
const b64 = Buffer.from(JSON.stringify(analise), 'utf8').toString('base64');
return [{ json: { edital_id: meta.edital_id, analise, b64 } }];
